31	public class EntityAttributeFingerprintBuilder {
32	
33	    private final HostRecordService hostRecordService;
34	    private final UserRecordService userRecordService;
35	    private final DynamicClientService dynamicClientService;
36	    private final MeterRegistry meterRegistry;
37	
38	    public FingerprintBuildResult build(IngestionRequest req) {
39	        Timer.Sample sample = Timer.start(meterRegistry);
40	        long startTime = System.nanoTime();
41	        try {
42	            String provided = req.getAttributeFingerprint();
43	            EntityType type = EntityType.valueOf(req.getEntityType().toUpperCase());
44	
45	            // If fingerprint is provided, no need loading data from DB
46	            if (provided != null && !provided.isBlank()) {
47	                return FingerprintBuildResult.builder()
48	                        .fingerprint(provided)
49	                        .build();
50	            }
51	
52	            HostAttribute hostAttribute = loadHostAttribute(req.getHostId());
53	            DynamicClientAttribute dynamicClientAttribute = loadDynamicClient(req.getAdapterId());
54	
55	            if (type == EntityType.HOST) {
56	                String fp = EntityUtil.calcFingerprint(hostAttribute, dynamicClientAttribute);
57	
58	                return FingerprintBuildResult.builder()
59	                        .fingerprint(fp)
60	                        .hostAttribute(hostAttribute)
61	                        .dynamicClientAttribute(dynamicClientAttribute)
62	                        .build();
63	            }
64	
65	            if (type == EntityType.USER_HOST_BINDING) {
66	                UserAttribute userAttribute = loadUserAttribute(req.getUserId());
67	
68	                String fp = EntityUtil.calcFingerprint(userAttribute, hostAttribute, dynamicClientAttribute);
69	
70	                return FingerprintBuildResult.builder()
71	                        .fingerprint(fp)
72	                        .hostAttribute(hostAttribute)
73	                        .userAttribute(userAttribute)
74	                        .dynamicClientAttribute(dynamicClientAttribute)
75	                        .build();
76	            }
77	
78	            throw new IllegalArgumentException("Unsupported entity type: " + req.getEntityType());
79	        } finally {
80	            long costMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime);
81	            log.info("Fingerprint build cost={} ms, entityType={}", costMs, req.getEntityType());
82	
83	            Timer timer = Timer.builder("ingestion_fingerprint_build_seconds")
84	                    .tag("entityType", EntityType.valueOf(req.getEntityType().toUpperCase()).name())
85	                    .register(meterRegistry);
86	            sample.stop(timer);
87	        }
88	    }
