public enum FingerprintCase {
    SAME_ATTR_LOCK,
    SAME_ATTR_NO_LOCK,
    DIFF_ATTR_LOCK,
    DIFF_ATTR_NO_LOCK;

    public static FingerprintCase of(boolean sameFingerprint, boolean lockAcquired) {
        if (sameFingerprint && lockAcquired) {
            return SAME_ATTR_LOCK;
        }
        if (sameFingerprint) {
            return SAME_ATTR_NO_LOCK;
        }
        if (lockAcquired) {
            return DIFF_ATTR_LOCK;
        }
        return DIFF_ATTR_NO_LOCK;
    }
